mapper.update:
UPDATE learning_task
SET phase_name = #{phaseName}, task_text = #{taskText}, focus_area = #{focusArea},
    completed = #{completed}, completed_at = #{completedAt}
WHERE id = #{id}

UPDATE learning_task
SET completed = 1, completed_at = NOW()
WHERE user_id = #{userId} AND phase_index = #{phaseIndex} AND task_index = #{taskIndex}

UPDATE learning_task
SET completed = 0, completed_at = NULL
WHERE user_id = #{userId} AND phase_index = #{phaseIndex} AND task_index = #{taskIndex}

mapper.select:
SELECT * FROM learning_task
WHERE user_id = #{userId} AND phase_index = #{phaseIndex}
ORDER BY task_index
